sql:
SELECT data_value 
FROM data_series 
ORDER BY period ASC;

SELECT period, data_value
FROM data_series
WHERE series_id = 1;

SELECT ds.series_id, st.series_title_name
FROM data_series ds
JOIN series_titles st ON ds.series_title_id = st.series_title_id;

SELECT series_title_name
FROM series_titles
WHERE series_title_id = 1;

SELECT series_title_name
FROM series_titles
WHERE series_title_id = 1;
